parameters.text:
=Assess the Acumatica certification level 
for this partner company:

Company: {{ $json.company_name }}
Record ID: {{ $json.record_id }}
Profile URL: {{ $json.profile_url }}
Current Cert: {{ $json.current_cert }}

Based on the company name and any available 
information, assign the most appropriate 
certification level.

Return ONLY this exact JSON:
{
  "record_id": "{{ $json.record_id }}",
  "company_name": "{{ $json.company_name }}",
  "cert_level": "Gold|Silver|Authorized|Unknown|N/A",
  "cert_score": 85,
  "rationale": "One clear reason for this level",
  "confidence": "High|Medium|Low"
}

parameters.jsCode:
const item = $input.first();
const original = $('Loop Over Items').first().json;

// Get AI output
let rawOutput = item.json.output || '';
let certData = {};

try {
  // Clean markdown if present
  if (typeof rawOutput === 'string') {
    rawOutput = rawOutput
      .replace(/```json/gi, '')
      .replace(/```/g, '')
      .trim();

    const start = rawOutput.indexOf('{');
    const end = rawOutput.lastIndexOf('}');

    if (start !== -1 && end !== -1) {
      certData = JSON.parse(
        rawOutput.substring(start, end + 1)
      );
    }
  } else if (typeof rawOutput === 'object') {
    certData = rawOutput;
  }
} catch(e) {
  return [{
    json: {
      record_id: original.record_id,
      company_name: original.company_name,
      cert_level: 'Unknown',
      cert_score: 0,
      rationale: 'AI parse failed: ' + e.message,
      error: true,
      skip: false
    }
  }];
}

// Valid certification levels
const validLevels = [
  'Gold', 'Silver', 'Authorized', 'Unknown', 'N/A'
];

// Normalize cert level
let certLevel = (certData.cert_level || 'Unknown')
  .trim();
if (!validLevels.includes(certLevel)) {
  certLevel = 'Unknown';
}

// Normalize cert score (0-100)
let certScore = parseInt(certData.cert_score) || 0;
if (certScore > 100) certScore = 100;
if (certScore < 0) certScore = 0;

// Validate score matches level
// Override score if doesn't match level
if (certLevel === 'Gold' && certScore < 80) {
  certScore = 85;
}
if (certLevel === 'Silver' && 
   (certScore < 50 || certScore > 79)) {
  certScore = 65;
}
if (certLevel === 'Authorized' && 
   (certScore < 25 || certScore > 49)) {
  certScore = 35;
}
if (certLevel === 'Unknown') certScore = 0;
if (certLevel === 'N/A') certScore = 0;

// Normalize confidence
const validConfidence = ['High', 'Medium', 'Low'];
let confidence = (certData.confidence || 'Medium')
  .trim();
if (!validConfidence.includes(confidence)) {
  confidence = 'Medium';
}

// Normalize profile URL
let profileUrl = (original.profile_url || '').trim();
if (profileUrl && !profileUrl.startsWith('https://')) {
  profileUrl = 'https://' + profileUrl;
}

return [{
  json: {
    record_id: original.record_id,
    company_name: certData.company_name || 
                  original.company_name,
    profile_url: profileUrl,
    cert_level: certLevel,
    cert_score: certScore,
    rationale: (certData.rationale || '')
                .substring(0, 300),
    confidence: confidence,
    previous_cert: original.current_cert || 'Unknown',
    cert_changed: certLevel !== original.current_cert,
    error: false,
    processed_at: new Date().toISOString()
  }
}];
